let b='';process.stdin.on\('data',c=>b+=c\);process.stdin.on\('end',\(\)=>{
  const d=JSON.parse\(b\);
  const products=d.data||[];
  products.forEach\(p=>{
    console.log\('\\n=== Product', p.id, p.name, '==='\);
    console.log\('  shopOfficeId' in p ? 'HAS shopOfficeId='+p.shopOfficeId : 'NO shopOfficeId'\);
    const variants=p.productVariants||[];
    console.log\('  Variants:', variants.length\);
    const combos={};
    variants.forEach\(v=>{
      const key=v.variantSize+'__'+v.variantColor;
      if\(!combos[key]\)combos[key]=[];
      combos[key].push\(v.id\);
    }\);
    Object.entries\(combos\).filter\(\([k,ids]\)=>ids.length>1\).forEach\(\([k,ids]\)=>{
      console.log\('  DUPLICATE:', k, 'ids:', ids.join\(','\)\);
    }\);
    const colors=new Set\(variants.map\(v=>v.variantColor\)\);
    console.log\('  Colors:', [...colors].join\(', '\)\);
  }\);
}\)")
